import {
  PassengerType,
  PassengerTypes,
} from '~app/domain/kernel/passengers/types/passengerType.type';
import { SeatType } from './legend.type';
import { SeatPositionTypes, SeatAssignmentStatus } from '../constants';
import { SeatAssignment } from './seatPassenger.type';
import {
  ShopSeatResponse,
  SeatMap as SeatMapAPI,
  Deck as DeckAPI,
  Passenger as PassengerAPI,
  Compartment as CompartmentAPI,
  Row as RowAPI,
  Seat as SeatAPI,
  Segment as SegmentAPI,
  SeatPrice,
  SeatMapDetail as SeatMapDetailAPI,
} from '../../contract/shop.type';
import { SeatAssignmentsPayload, SelectedSeatPassengerPayload } from '../../soa.api.type';

export interface TravixDecimal {
  readonly number: string;
}

export interface SeatMapDetail {
  readonly currency: string;
  readonly seatCurrency: string;
  readonly seatPrices: readonly SeatPrice[];
  readonly seatDisplayPrices: {
    readonly [key: string]: TravixDecimal;
  };
  readonly segmentId: number;
  readonly segmentIdentifier?: string;
  readonly status: string;
  readonly markUp: TravixDecimal | null;
}

interface SeatPriceAPI {
  readonly [key: string]: TravixDecimal;
}

export interface SeatPriceMap {
  readonly [passengerIndex: string]: number | undefined;
}

interface PurchasedSeat {
  readonly seatKey: string;
  readonly status: SeatAssignmentStatus;
  readonly segmentId: number;
  readonly segmentIdentifier?: string;
  readonly pnrId: string;
}

export interface PurchasedSeatMultiPnr {
  readonly seatKey: string;
  readonly status: SeatAssignmentStatus;
  readonly segmentId: number;
  readonly segmentIdentifier?: string;
}

interface SeatPassengerWithDetail {
  readonly passengerIndex: string;
  readonly type: PassengerTypes;
  readonly seatAssignments: readonly SeatAssignment[];
  readonly seatMapDetails: readonly SeatMapDetail[];
}

export interface SeatPassenger {
  readonly passengerIndex: string;
  readonly type: PassengerTypes;
  readonly seatAssignments: readonly SeatAssignment[];
}

type SeatPositionType =
  | SeatPositionTypes.Aisle
  | SeatPositionTypes.Center
  | SeatPositionTypes.Window;

interface Seat {
  readonly groupedSeats?: readonly Seat[];
  readonly isFacility: boolean;
  readonly isSelectable: boolean;
  readonly hasBulkhead: boolean;
  readonly priceMap?: SeatPriceMap;
  readonly seatKey: string;
  readonly seatPosition: SeatPositionType;
  readonly type: SeatType;
  readonly unsuitablePassengerTypes?: readonly PassengerType[];
}

interface SeatSelection {
  readonly seatKey: string;
  readonly seatPrice: number;
  readonly passengerIndex: string;
  readonly firstName: string;
  readonly lastName: string;
  readonly segmentId: number;
  readonly segmentIdentifier: string;
  readonly combinationId: string;
  readonly pnrId: string;
  readonly pnr: string;
  readonly type: SeatType;
  readonly status: SeatAssignmentStatus;
}

interface SelectedSeatProduct {
  readonly seatKey: string;
  readonly passengerIndex: string;
}

export interface SelectSeatAssignment {
  readonly segmentIdentifier: string;
  readonly selectedSeatProducts: readonly SelectedSeatProduct[];
}

export interface ChangeSeatProductsPayload {
  readonly orderNumber: string;
  readonly postSaleShoppingCartId: string;
  readonly seatAssignments: readonly SelectSeatAssignment[];
}

export {
  SeatMapAPI,
  DeckAPI,
  PassengerAPI,
  CompartmentAPI,
  RowAPI,
  SeatAPI,
  SegmentAPI,
  SeatMapDetailAPI,
  SeatPriceAPI,
  ShopSeatResponse,
  SeatPassengerWithDetail,
  SeatSelection,
  Seat,
  SeatPositionType,
  SeatPrice,
  PurchasedSeat,
  SelectedSeatPassengerPayload,
  SeatAssignmentsPayload,
  SelectedSeatProduct,
};

