import { PurchasedSeat } from '~app/domain/ancillary/postSale/types/seat.type';
import { SeatAssignment } from '~app/domain/account/passengers/types/seatAssignment.type';
import { SeatAssignmentStatus } from '../constants';

export const purchasedSeatTransform = {
  toEntity: (
    seatAssignmentsApi: readonly SeatAssignment[],
    pnrId: string,
  ): readonly PurchasedSeat[] =>
    seatAssignmentsApi.map((item) => ({
      status: SeatAssignmentStatus.PURCHASED,
      seatKey: item.seat,
      segmentId: item.segmentId,
      segmentIdentifier: item.segmentIdentifier,
      pnrId,
    })),
};

content.thinking:
Looking at the code:

1. The `purchasedSeatTransform.toEntity` function returns objects with:
   - `status: SeatAssignmentStatus.PURCHASED`
   - `seatKey: item.seat`
   - `segmentId: item.segmentId`
   - `segmentIdentifier: item.segmentIdentifier`
   - `pnrId`

2. The test expects the result to be:
```js
[
  { seatKey: '2B', segmentId: 1, pnrId: pnrId1Fixture, status: SeatAssignmentStatus.PURCHASED },
  { seatKey: '2B', segmentId: 2, pnrId: pnrId1Fixture, status: SeatAssignmentStatus.PURCHASED },
]
```

3. The `PurchasedSeat` interface (from the modified seat.type.ts) has:
```typescript
interface PurchasedSeat {
  readonly seatKey: string;
  readonly status: SeatAssignmentStatus;
  readonly segmentId: number;
  readonly segmentIdentifier?: string;
  readonly pnrId: string;
}
```

The issue is that the test expectation doesn't include `segmentIdentifier` which is now part of the `PurchasedSeat` interface. The test should include `segmentIdentifier` in the expected output.

Let me also check the fixture to see what data it provides.

